    shards: [PostingShard; 64],          // same sharding as AtomMemory
    arena: boxcar::Vec<EntangledHVec>,   // stores the composite vectors
    triple_refs: boxcar::Vec<(u32, u32, u32)>,  // (s_id, r_id, o_id) per composite
